THOUGHT: The miscompilation happens when InstCombine merges GEPs across a PHI and incorrectly propagates "inbounds" even though not all incoming GEPs are inbounds. In InstCombinePHI.cpp, foldPHIArgGEPIntoPHI already intersects no-wrap flags (NW) but not inbounds. I will patch the function to track AllInBounds (initialized from the first GEP), AND it with each incoming GEP’s isInBounds(), and set the merged GEP inbounds only if AllInBounds is true. Then I will submit the patch.

```bash
sed -i 's/^\(\s*GEPNoWrapFlags NW = FirstInst->getNoWrapFlags();\)$/\1
  bool AllInBounds = FirstInst->isInBounds();/' llvm/lib/Transforms/InstCombine/InstCombinePHI.cpp && sed -i 's/^\(\s*NW &= GEP->getNoWrapFlags();\)$/\1
    AllInBounds &= GEP->isInBounds();/' llvm/lib/Transforms/InstCombine/InstCombinePHI.cpp && awk 'BEGIN{print "Applying flag propagation for inbounds..."} /GetElementPtrInst::Create\(FirstInst->getSourceElementType\)/ && c==0{print; c=1; next} {print}' llvm/lib/Transforms/InstCombine/InstCombinePHI.cpp > /tmp/InstCombinePHI.cpp.tmp && mv /tmp/InstCombinePHI.cpp.tmp llvm/lib/Transforms/InstCombine/InstCombinePHI.cpp && sed -i '/GetElementPtrInst::Create(FirstInst->getSourceElementType/,/PHIArgMergedDebugLoc/ s/PHIArgMergedDebugLoc(NewGEP, PN);/  if (NW.hasNoUnsignedWrap()) NewGEP->setHasNoUnsignedWrap(true);
  if (NW.hasNoSignedWrap()) NewGEP->setHasNoSignedWrap(true);
  if (AllInBounds) NewGEP->setIsInBounds(true);

  PHIArgMergedDebugLoc(NewGEP, PN);/' llvm/lib/Transforms/InstCombine/InstCombinePHI.cpp && submit-patch
```

